ValidationRule.errorConditionFormula:
AND(
    NOT(
        OR(
            AND(
                NOT(ISBLANK(TEXT( InquiryType5__c ))),
                NOT(ISBLANK( Date5__c )),
                LEN ( URL5__c ) > 0
            ),
            AND(
                ISBLANK(TEXT( InquiryType5__c )),
                ISBLANK( Date5__c ),
                LEN ( URL5__c ) = 0
            )
        )
    ),
    NOT(
        OR(
            $Profile.Name = 'システム管理者',
            $Profile.Name = 'データ移行管理者'
        )
    )
)
